 23→public class Address implements Serializable {
 24→    private static final Pattern ATOM = Pattern.compile("^(?:[a-zA-Z0-9!#$%&'*+\\-/=?^_`{|}~]|\\s)+$");
 25→
 26→    /**
 27→     * Immutable empty {@link Address} array
 28→     */
 29→    private static final Address[] EMPTY_ADDRESS_ARRAY = new Address[0];
 30→
 31→    @NotNull
 32→    private String mAddress;
 33→
 34→    private String mPersonal;
 35→
 36→    public Address(Address address) {
 37→        mAddress = address.mAddress;
 38→        mPersonal = address.mPersonal;
 39→    }
