207→    /**
208→     * Unpacks an address list previously packed with packAddressList()
209→     * @param addressList Packed address list.
210→     * @return Unpacked list.
211→     */
212→    public static Address[] unpack(String addressList) {
213→        if (addressList == null) {
214→            return new Address[] { };
215→        }
216→        List<Address> addresses = new ArrayList<>();
217→        int length = addressList.length();
218→        int pairStartIndex = 0;
219→        int pairEndIndex = 0;
220→        int addressEndIndex = 0;
221→        while (pairStartIndex < length) {
222→            pairEndIndex = addressList.indexOf(",\u0001", pairStartIndex);
223→            if (pairEndIndex == -1) {
224→                pairEndIndex = length;
225→            }
226→            addressEndIndex = addressList.indexOf(";\u0001", pairStartIndex);
227→            String address = null;
228→            String personal = null;
229→            if (addressEndIndex == -1 || addressEndIndex > pairEndIndex) {
230→                address = addressList.substring(pairStartIndex, pairEndIndex);
231→            } else {
232→                address = addressList.substring(pairStartIndex, addressEndIndex);
233→                personal = addressList.substring(addressEndIndex + 2, pairEndIndex);
234→            }
235→            addresses.add(new Address(address, personal, false));
236→            pairStartIndex = pairEndIndex + 2;
237→        }
238→        return addresses.toArray(new Address[addresses.size()]);
239→    }
