241→    /**
242→     * Packs an address list into a String that is very quick to read
243→     * and parse. Packed lists can be unpacked with unpackAddressList()
244→     * The packed list is a ",\u0001" separated list of:
245→     * address;\u0001personal
246→     * @param addresses Array of addresses to pack.
247→     * @return Packed addresses.
248→     */
249→    public static String pack(Address[] addresses) {
250→        if (addresses == null) {
251→            return null;
252→        }
253→        StringBuilder sb = new StringBuilder();
254→        for (int i = 0, count = addresses.length; i < count; i++) {
255→            Address address = addresses[i];
256→            sb.append(address.getAddress());
257→            String personal = address.getPersonal();
258→            if (personal != null) {
259→                sb.append(";\u0001");
260→                // Escape quotes in the address part on the way in
261→                personal = personal.replaceAll("\"", "\\\"");
262→                sb.append(personal);
263→            }
264→            if (i < count - 1) {
265→                sb.append(",\u0001");
266→            }
267→        }
268→        return sb.toString();
269→    }
