","new_string":"internal class UserInputEmailAddressParser {

    @Throws(NonAsciiEmailAddressException::class)
    fun parse(input: String): List<Address> {
        return Address.parseUnencoded(input)
            .mapNotNull { address ->
                when {
                    address.isIncomplete() -> null
                    address.isNonAsciiAddress() -> throw NonAsciiEmailAddressException(address.address)
                    else -> address.toRfc5321AddressOrNull()
                }
            }
    }

    private fun Address.toRfc5321AddressOrNull(): Address? {
        val parsedAddress = Address.parse(toEncodedString()).firstOrNull() ?: return null
        return parsedAddress.takeIf { it.isValidRfc5321Mailbox() }
    }

    private fun Address.isValidRfc5321Mailbox(): Boolean {
        val mailbox = address
        val atIndex = mailbox.lastIndexOf('@')

        if (atIndex <= 0 || atIndex == mailbox.lastIndex) return false

        val localPart = mailbox.substring(0, atIndex)
        val domain = mailbox.substring(atIndex + 1)

        if (localPart.isBlank() || domain.isBlank()) return false

        // RFC 5321 mailbox should not contain whitespace or control characters.
        if (mailbox.any { it <= '\u001F' || it == '\u007F' || it.isWhitespace() }) return false

        return isValidRfc5321Domain(domain)
    }

    private fun isValidRfc5321Domain(domain: String): Boolean {
        if (domain.length > 255) return false

        if (domain.startsWith("[") && domain.endsWith("]")) {
            return isValidAddressLiteral(domain)
        }

        if (domain.startsWith('.') || domain.endsWith('.')) return false

        val labels = domain.split('.')
        if (labels.any { it.isEmpty() }) return false

        return labels.all { isValidDomainLabel(it) }
    }

    private fun isValidDomainLabel(label: String): Boolean {
        if (label.length !in 1..63) return false
        if (!label.first().isLetterOrDigit() || !label.last().isLetterOrDigit()) return false

        for (c in label) {
            if (!(c.isLetterOrDigit() || c == '-')) return false
        }

        return true
    }

    private fun isValidAddressLiteral(domainLiteral: String): Boolean {
        // e.g. [127.0.0.1] or [IPv6:2001:db8::1]
        val inner = domainLiteral.substring(1, domainLiteral.length - 1)

        if (inner.isEmpty()) return false
        if (inner.any { it <= '\u001F' || it == '\u007F' || it.isWhitespace() }) return false

        // Reject obvious invalid characters for a domain literal.
        if (inner.contains('/')) return false

        return true
    }

    private fun Address.isIncomplete() = hostname.isNullOrBlank()

    private fun Address.isNonAsciiAddress() = !CharsetUtil.isASCII(address)
}
