import assertk.assertThat
import assertk.assertions.containsExactly
import assertk.assertions.isEmpty
import com.fsck.k9.mail.Address
import kotlin.test.Test

class UserInputEmailAddressParserRfc5321ValidationTest {
    private val parser = UserInputEmailAddressParser()

    @Test
    fun `email address with trailing slash in domain is rejected`() {
        val addresses = parser.parse("user@domain.example/")

        assertThat(addresses).isEmpty()
    }

    @Test
    fun `email address with slash in local part is accepted`() {
        val addresses = parser.parse("user/name@domain.example")

        assertThat(addresses).containsExactly(Address("user/name@domain.example"))
    }
}
