 18→import org.apache.james.mime4j.dom.address.MailboxList;
 19→import org.apache.james.mime4j.field.address.DefaultAddressParser;
 20→import org.jetbrains.annotations.NotNull;
 21→import org.jetbrains.annotations.VisibleForTesting;
 22→
 23→public class Address implements Serializable {
 24→    private static final Pattern ATOM = Pattern.compile("^(?:[a-zA-Z0-9!#$%&'*+\\-/=?^_`{|}~]|\\s)+$");
 25→
 26→    /**
 27→     * Immutable empty {@link Address} array
 28→     */
 29→    private static final Address[] EMPTY_ADDRESS_ARRAY = new Address[0];
 30→
 31→    @NotNull
 32→    private String mAddress;
 33→
 34→    private String mPersonal;
 35→
 36→    public Address(Address address) {
 37→        mAddress = address.mAddress;
 38→        mPersonal = address.mPersonal;
 39→    }
 40→
 41→    public Address(String address, String personal) {
 42→        this(address, personal, true);
 43→    }
 44→
 45→    public Address(String address) {
 46→        this(address, null, true);
 47→    }
 48→
 49→    private Address(String address, String personal, boolean parse) {
 50→        if (address == null) {
 51→            throw new IllegalArgumentException("address");
 52→        }
 53→        if (parse) {
 54→            Rfc822Token[] tokens =  Rfc822Tokenizer.tokenize(address);
 55→            if (tokens.length > 0) {
 56→                Rfc822Token token = tokens[0];
 57→                if (token.getAddress() == null) {
 58→                    throw new IllegalArgumentException("token.getAddress()");
 59→                }
 60→                mAddress = token.getAddress();
 61→                String name = token.getName();
 62→                if (!TextUtils.isEmpty(name)) {
 63→                    /*
 64→                     * Don't use the "personal" argument if "address" is of the form:
 65→                     * James Bond <james.bond@mi6.uk>
 66→                     *
 67→                     * See issue 2920
 68→                     */
 69→                    mPersonal = name;
 70→                } else {
 71→                    mPersonal = (personal == null) ? null : personal.trim();
 72→                }
 73→            } else {
 74→                Timber.e("Invalid address: %s", address);
 75→            }
 76→        } else {
 77→            mAddress = address;
 78→            mPersonal = personal;
 79→        }
 80→    }
 81→
 82→    public String getAddress() {
 83→        return mAddress;
 84→    }
 85→
 86→    public String getHostname() {
 87→        if (mAddress == null) {
 88→            return null;
 89→        }
 90→
 91→        int hostIdx = mAddress.lastIndexOf("@");
 92→
 93→        if (hostIdx == -1) {
 94→            return null;
 95→        }
 96→
 97→        return mAddress.substring(hostIdx + 1);
 98→    }
 99→
100→    public String getPersonal() {
101→        return mPersonal;
102→    }
103→
104→    /**
105→     * Parse a comma separated list of email addresses in human readable format and return an
106→     * array of Address objects, RFC-822 encoded.
107→     *
108→     * @param addressList
109→     * @return An array of 0 or more Addresses.
110→     */
111→    public static Address[] parseUnencoded(String addressList) {
112→        List<Address> addresses = new ArrayList<>();
113→        if (!TextUtils.isEmpty(addressList)) {
114→            Rfc822Token[] tokens = Rfc822Tokenizer.tokenize(addressList);
115→            for (Rfc822Token token : tokens) {
116→                String address = token.getAddress();
117→                if (!TextUtils.isEmpty(address)) {
118→                    String name = TextUtils.isEmpty(token.getName()) ? null : token.getName();
119→                    addresses.add(new Address(token.getAddress(), name, false));
120→                }
121→            }
122→        }
123→        return addresses.toArray(EMPTY_ADDRESS_ARRAY);
124→    }
125→
126→    /**
127→     * Parse a comma separated list of addresses in RFC-822 format and return an
128→     * array of Address objects.
129→     *
130→     * @param addressList
131→     * @return An array of 0 or more Addresses.
132→     */
133→    public static Address[] parse(String addressList) {
134→        if (TextUtils.isEmpty(addressList)) {
135→            return EMPTY_ADDRESS_ARRAY;
136→        }
137→        List<Address> addresses = new ArrayList<>();
138→        try {
139→            MailboxList parsedList =  DefaultAddressParser.DEFAULT.parseAddressList(addressList, DecodeMonitor.SILENT).flatten();
140→
141→            for (int i = 0, count = parsedList.size(); i < count; i++) {
142→                Mailbox mailbox = parsedList.get(i);
143→                addresses.add(new Address(mailbox.getLocalPart() + "@" + mailbox.getDomain(), mailbox.getName(), false));
144→            }
145→        } catch (MimeException pe) {
146→            Timber.e(pe, "MimeException in Address.parse()");
147→            // broken addresses are never added to the resulting array
148→        }
149→        return addresses.toArray(EMPTY_ADDRESS_ARRAY);
150→    }
151→
152→    @Override
153→    public boolean equals(Object o) {
154→        if (this == o) {
155→            return true;
156→        }
157→
158→        if (o == null || getClass() != o.getClass()) {
159→            return false;
160→        }
161→
162→        Address address = (Address) o;
163→
164→        if (mAddress != null ? !mAddress.equals(address.mAddress) : address.mAddress != null) {
165→            return false;
166→        }
167→
168→        return mPersonal != null ? mPersonal.equals(address.mPersonal) : address.mPersonal == null;
169→    }
170→
171→    @Override
172→    public int hashCode() {
173→        int hash = 0;
174→        if (mAddress != null) {
175→            hash += mAddress.hashCode();
176→        }
177→        if (mPersonal != null) {
178→            hash += 3 * mPersonal.hashCode();
179→        }
180→        return hash;
181→    }
182→
183→    @Override
184→    public String toString() {
185→        if (!TextUtils.isEmpty(mPersonal)) {
186→            return quoteAtoms(mPersonal) + " <" + mAddress + ">";
187→        } else {
188→            return mAddress;
189→        }
190→    }
191→
192→    public static String toString(Address[] addresses) {
193→        if (addresses == null) {
194→            return null;
195→        }
196→        return TextUtils.join(", ", addresses);
197→    }
198→
199→    public String toEncodedString() {
200→        if (!TextUtils.isEmpty(mPersonal)) {
201→            return EncoderUtil.encodeAddressDisplayName(mPersonal) + " <" + mAddress + ">";
202→        } else {
203→            return mAddress;
204→        }
205→    }
206→
207→    /**
208→     * Unpacks an address list previously packed with packAddressList()
209→     * @param addressList Packed address list.
210→     * @return Unpacked list.
211→     */
212→    public static Address[] unpack(String addressList) {
213→        if (addressList == null) {
214→            return new Address[] { };
215→        }
216→        List<Address> addresses = new ArrayList<>();
217→        int length = addressList.length();
218→        int pairStartIndex = 0;
219→        int pairEndIndex = 0;
220→        int addressEndIndex = 0;
221→        while (pairStartIndex < length) {
222→            pairEndIndex = addressList.indexOf(",\u0001", pairStartIndex);
223→            if (pairEndIndex == -1) {
224→                pairEndIndex = length;
225→            }
226→            addressEndIndex = addressList.indexOf(";\u0001", pairStartIndex);
227→            String address = null;
228→            String personal = null;
229→            if (addressEndIndex == -1 || addressEndIndex > pairEndIndex) {
230→                address = addressList.substring(pairStartIndex, pairEndIndex);
231→            } else {
232→                address = addressList.substring(pairStartIndex, addressEndIndex);
233→                personal = addressList.substring(addressEndIndex + 2, pairEndIndex);
234→            }
235→            addresses.add(new Address(address, personal, false));
236→            pairStartIndex = pairEndIndex + 2;
237→        }
238→        return addresses.toArray(new Address[addresses.size()]);
239→    }
240→
241→    /**
242→     * Packs an address list into a String that is very quick to read
243→     * and parse. Packed lists can be unpacked with unpackAddressList()
244→     * The packed list is a ",\u0001" separated list of:
245→     * address;\u0001personal
246→     * @param addresses Array of addresses to pack.
247→     * @return Packed addresses.
248→     */
249→    public static String pack(Address[] addresses) {
250→        if (addresses == null) {
251→            return null;
252→        }
253→        StringBuilder sb = new StringBuilder();
254→        for (int i = 0, count = addresses.length; i < count; i++) {
255→            Address address = addresses[i];
256→            sb.append(address.getAddress());
257→            String personal = address.getPersonal();
258→            if (personal != null) {
259→                sb.append(";\u0001");
260→                // Escape quotes in the address part on the way in
261→                personal = personal.replaceAll("\"", "\\\"");
262→                sb.append(personal);
263→            }
264→            if (i < count - 1) {
265→                sb.append(",\u0001");
266→            }
267→        }
268→        return sb.toString();
269→    }
270→
271→    /**
272→     * Quote a string, if necessary, based upon the definition of an "atom," as defined by RFC2822
273→     * (http://tools.ietf.org/html/rfc2822#section-3.2.4). Strings that consist purely of atoms are
274→     * left unquoted; anything else is returned as a quoted string.
275→     * @param text String to quote.
276→     * @return Possibly quoted string.
277→     */
278→    public static String quoteAtoms(final String text) {
279→        if (ATOM.matcher(text).matches()) {
280→            return text;
281→        } else {
282→            return quoteString(text);
283→        }
284→    }
285→
286→    /**
287→     * Ensures that the given string starts and ends with the double quote character.
288→     * The string is not modified in any way except to add the double quote character to start
289→     * and end if it's not already there.
290→     * sample -> "sample"
291→     * "sample" -> "sample"
292→     * ""sample"" -> ""sample""
293→     * "sample"" -> "sample"
294→     * sa"mp"le -> "sa"mp"le"
295→     * "sa"mp"le" -> "sa"mp"le"
296→     * (empty string) -> ""
297→     * " -> """
298→     * @param s
299→     * @return
300→     */
301→    @VisibleForTesting
302→    static String quoteString(String s) {
303→        if (s == null) {
304→            return null;
305→        }
306→        if (!s.matches("^\".*\"$")) {
307→            return "\"" + s + "\"";
308→        } else {
309→            return s;
310→        }
311→    }
312→}
